# demo_geometry.pyimport streamlit as stfrom bridge import MGEPlusBridgebridge = MGEPlusBridge()st.set_page_config(page_title="ANIMA TESTIS • NACO 2026", layout="wide")st.title("ANIMA TESTIS — Dual Testimony Coherence")st.markdown("**Real MGE+ Geometry • Founder + Investor Alignment**")col1, col2 = st.columns(2)with col1:    st.subheader("Founder / Founder Team Testimony")    founder_text = st.text_area("Paste Founder Testimony", height=300, key="founder")with col2:    st.subheader("Investor (VC / Angel) Testimony")    investor_text = st.text_area("Paste Investor Testimony", height=300, key="investor")if st.button("Compute Shared Coherence", type="primary"):    if not founder_text.strip() or not investor_text.strip():        st.error("Please provide both testimonies.")    else:        with st.spinner("Computing real geometry..."):            analysis = bridge.run_dual_analysis(founder_text, investor_text)                        st.success(f"**Shared Coherence Score: {analysis['score']}%**")                        st.write("**Alignment Gap**")            st.info(analysis['gap'])                        st.write("**Founder Adjustment**")            st.write(analysis['founder_adjustment'])                        st.write("**Investor Adjustment**")            st.write(analysis['investor_adjustment'])                        st.metric("Projected Improved Coherence", f"{analysis['improved_score']}%")st.caption("ANIMA TESTIS • Real MGE+ Xi Geometry • The Quadratic • NACO 2026")